};

export const NameField = ({ actionPage, isPreview = false }: Props) => {
  const { trigger, watch } = useFormContext();
  const { t } = useTranslation('customFields');
  const donorProfile = isPreview ? null : watch('donorProfile');
  const title = watch('title');
  const isDonation = isDonationPage(actionPage?.pageType);

  const {
    displayName = true,
    includeMiddleName = false,
    includeSuffix = false,
    includeTitle = false,
    requireName = false,
    requireTitle = false,
  } = actionPage?.fieldConfiguration || {};

  // leave this shims in so that when we split first / last name requirements
  // it is easier
  const includeFirstName = displayName;
  const includeLastName = displayName;
  const requireFirstAndLastName = requireName;

  const titles = useMemo(() => {
    const options = t('name.titles', { returnObjects: true });

    return [
      {
        label: '-',
        value: '',
      },
      ...(Array.isArray(options) ? options : [options]).map((option) => ({
        label: option,
        value: option,
      })),
    ];
  }, [t]);

  useEffect(() => {
    if (title) {
      trigger('title');
    }
  }, [title, trigger]);

  return (
    <>
      {(includeFirstName || includeLastName) &&
      (!donorProfile?.firstName || !donorProfile?.lastName) ? (
        <div className="flex w-full gap-2">
          {includeFirstName && (!donorProfile || !donorProfile.firstName) ? (
            <div className="flex grow">
              <FormInputControl
                formControlProps={{ className: 'mb-0' }}
                isRequired={isDonation || requireFirstAndLastName}
                label={t('name.first')}
                name="firstName"
              />
            </div>
          ) : null}
          {includeLastName && (!donorProfile || !donorProfile.lastName) ? (
            <div className="flex grow">
              <FormInputControl
                formControlProps={{ className: 'mb-0' }}
                isRequired={isDonation || requireFirstAndLastName}
                label={t('name.last')}
                name="lastName"
              />
            </div>
          ) : null}
        </div>
      ) : null}
      {(includeMiddleName || includeSuffix || includeTitle || requireTitle) && (
        <div className="mt-2 flex items-stretch gap-2">
          {includeMiddleName && (
            <div className="flex w-full">
              <FormInputControl
                formControlProps={{ className: 'mb-0' }}
                label={t('name.middle')}
                name="middleName"
              />
            </div>
          )}
          {includeTitle && (
            <div className="w-[106px] min-w-[106px] max-w-[106px]">
              <FormSelectControl
                className="w-[106px] min-w-[106px] max-w-[106px]"
                formControlProps={{ className: 'mb-0' }}
                isRequired={requireTitle}
                label={t('name.title')}
                name="title"
                options={titles}
              />
            </div>
          )}
          {includeSuffix && (
            <div className="w-[106px] min-w-[106px] max-w-[106px]">
              <FormInputControl
                formControlProps={{ className: 'mb-0' }}
                label={t('name.suffix')}
                name="suffix"
              />
            </div>
          )}
        </div>
      )}
    </>
  );
};

